// ============================================================
// N8N CODE NODE — JSON Response Formatter (HTML mode)
// Ganti Parse Mode di Send Message node ke: HTML
// ============================================================

// Helper: escape karakter HTML supaya tidak rusak di Telegram
function e(str) {
  if (str === null || str === undefined) return "";
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function bold(str)   { return `<b>${e(str)}</b>`; }
function italic(str) { return `<i>${e(str)}</i>`; }
function code(str)   { return `<code>${e(str)}</code>`; }

// ── Parse JSON dari output AI Agent ──────────────────────────
const raw = $input.item.json.output || $input.item.json.text || "";

let data;
try {
  const cleaned = raw
    .replace(/```json\n?/g, "")
    .replace(/```\n?/g, "")
    .trim();

  const jsonStart = cleaned.indexOf("{");
  const jsonEnd   = cleaned.lastIndexOf("}");
  data = JSON.parse(cleaned.substring(jsonStart, jsonEnd + 1));
} catch (err) {
  return [{
    json: {
      formatted_message: e(raw) || "⚠️ Maaf, terjadi kesalahan saat memproses respons.",
      parse_mode: "HTML"
    }
  }];
}

let msg = "";

// ── HARGA SAHAM ──────────────────────────────────────────────
if (data.harga !== undefined) {
  const up = !String(data.change_pct || "").startsWith("-");
  msg = `📈 ${bold(data.ticker)}\n`
      + `💰 Harga: ${bold(data.harga)}\n`
      + `${up ? "🟢" : "🔴"} ${e(data.change)} (${e(data.change_pct)})\n`
      + `📊 Vol: ${e(data.volume)}\n`
      + `🕐 ${e(data.last_update)}`;
}

// ── SENTIMEN ─────────────────────────────────────────────────
else if (data.sentimen !== undefined && data.ticker !== undefined) {
  const sEmoji = { bullish:"🟢", bearish:"🔴", neutral:"🟡" }[data.sentimen] || "⚪";
  const cEmoji = { HIGH:"🔥", MEDIUM:"✅", LOW:"⚠️" }[data.confidence] || "";
  const positif = (data.faktor_positif || []).map(p => `• ${e(p)}`).join("\n");
  const risiko  = (data.faktor_risiko  || []).map(r => `• ${e(r)}`).join("\n");

  msg = `${sEmoji} ${bold("Sentimen " + data.ticker + ": " + data.sentimen.toUpperCase())}\n`
      + `${cEmoji} Confidence: ${e(data.confidence)}\n\n`
      + `📝 ${e(data.ringkasan)}\n\n`
      + (positif ? `✅ ${bold("Positif:")}\n${positif}\n\n` : "")
      + (risiko  ? `⚠️ ${bold("Risiko:")}\n${risiko}\n\n`  : "")
      + `💡 ${bold("Saran:")} ${e(data.saran?.aksi?.toUpperCase())} — ${e(data.saran?.alasan)}\n\n`
      + italic(data.disclaimer || "Bukan rekomendasi investasi. DYOR.");
}

// ── FAQ EDUKASI ───────────────────────────────────────────────
else if (data.istilah !== undefined) {
  const related = (data.related_terms || []).map(t => e(t)).join(", ");
  msg = `📚 ${bold(data.istilah)}\n\n`
      + `${e(data.definisi)}\n\n`
      + `💡 ${bold("Contoh:")} ${e(data.contoh)}\n\n`
      + `🎯 ${bold("Tips:")} ${e(data.tips)}\n\n`
      + (related ? italic("Terkait: " + related) : "");
}

// ── PORTFOLIO ─────────────────────────────────────────────────
else if (data.holdings !== undefined) {
  const rows = (data.holdings || []).map(h => {
    const sEmoji = { above_target:"🎯", at_target:"✅", on_track:"📌" }[h.status] || "📌";
    return `${sEmoji} ${bold(h.ticker)} — Beli: ${e(String(h.harga_beli))} | Target: ${e(String(h.harga_target))} | ${e(String(h.lot))} lot`;
  }).join("\n");

  msg = `📋 ${bold("Watchlist Portfolio")}\n`
      + `${italic(data.total_saham + " saham")}\n\n`
      + `${rows}\n\n`
      + `📊 ${e(data.summary)}`;
}

// ── REKOMENDASI ───────────────────────────────────────────────
else if (data.rating !== undefined) {
  const rEmoji = { strong_buy:"🚀", buy:"🟢", hold:"🟡", sell:"🔴", strong_sell:"💀" }[data.rating] || "⚪";
  msg = `${rEmoji} ${bold(data.ticker + " — " + data.rating.toUpperCase())}\n`
      + `🎯 Target: Rp ${e(String(data.target_price))} | ${e(data.time_horizon)} term\n\n`
      + `📝 ${e(data.thesis)}\n\n`
      + `🟢 Bull: ${e(data.bull_case)}\n`
      + `🔴 Bear: ${e(data.bear_case)}\n\n`
      + `Confidence: ${e(data.confidence)}\n`
      + italic(data.disclaimer || "Bukan rekomendasi investasi. DYOR.");
}

// ── FALLBACK OUT OF SCOPE ─────────────────────────────────────
else if (data.status === "out_of_scope") {
  const list = (data.saran || []).map(s => `• ${e(s)}`).join("\n");
  msg = `🤖 ${e(data.pesan)}\n\nCoba tanya:\n${list}`;
}

// ── FALLBACK DATA NOT FOUND ───────────────────────────────────
else if (data.status === "data_not_found") {
  const list = (data.kemungkinan_penyebab || []).map(p => `• ${e(p)}`).join("\n");
  msg = `⚠️ ${bold(data.pesan)}\n\n`
      + `Input: ${code(data.input)}\n\n`
      + `Kemungkinan penyebab:\n${list}\n\n`
      + `💡 ${e(data.saran)}`;
}

// ── DEFAULT ───────────────────────────────────────────────────
else {
  msg = e(raw);
}

return [{
  json: {
    formatted_message: msg,
    parse_mode: "HTML",
    raw_json: data
  }
}];
